import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Quick Start Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user/quick-start.md","filePath":"user/quick-start.md","lastUpdated":1775719799000}'),n={name:"user/quick-start.md"};function r(o,e,l,u,h,d){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="quick-start-guide" tabindex="-1">Quick Start Guide <a class="header-anchor" href="#quick-start-guide" aria-label="Permalink to &quot;Quick Start Guide&quot;">​</a></h1><p>Welcome to RustChat! This guide will get you up and running quickly.</p><h2 id="signing-in" tabindex="-1">Signing In <a class="header-anchor" href="#signing-in" aria-label="Permalink to &quot;Signing In&quot;">​</a></h2><ol><li>Navigate to your team&#39;s RustChat URL (e.g., <code>https://chat.yourcompany.com</code>)</li><li>Enter your email and password</li><li>Or use SSO if your organization has configured it</li></ol><h2 id="understanding-the-interface" tabindex="-1">Understanding the Interface <a class="header-anchor" href="#understanding-the-interface" aria-label="Permalink to &quot;Understanding the Interface&quot;">​</a></h2><h3 id="left-sidebar" tabindex="-1">Left Sidebar <a class="header-anchor" href="#left-sidebar" aria-label="Permalink to &quot;Left Sidebar&quot;">​</a></h3><ul><li><strong>Teams:</strong> Switch between different teams</li><li><strong>Channels:</strong> Public and private channels you&#39;re a member of</li><li><strong>Direct Messages:</strong> 1:1 and group conversations</li></ul><h3 id="center-pane" tabindex="-1">Center Pane <a class="header-anchor" href="#center-pane" aria-label="Permalink to &quot;Center Pane&quot;">​</a></h3><ul><li><strong>Message History:</strong> Scroll through past messages</li><li><strong>Composer:</strong> Type and send messages at the bottom</li></ul><h3 id="right-sidebar-rhs" tabindex="-1">Right Sidebar (RHS) <a class="header-anchor" href="#right-sidebar-rhs" aria-label="Permalink to &quot;Right Sidebar (RHS)&quot;">​</a></h3><ul><li>Opens for threads, search results, and user profiles</li></ul><h2 id="your-first-actions" tabindex="-1">Your First Actions <a class="header-anchor" href="#your-first-actions" aria-label="Permalink to &quot;Your First Actions&quot;">​</a></h2><h3 id="set-your-status" tabindex="-1">Set Your Status <a class="header-anchor" href="#set-your-status" aria-label="Permalink to &quot;Set Your Status&quot;">​</a></h3><p>Click your avatar to set your status:</p><ul><li>🟢 Online</li><li>🟡 Away</li><li>🔴 Do Not Disturb</li><li>⚪ Offline</li></ul><h3 id="join-a-channel" tabindex="-1">Join a Channel <a class="header-anchor" href="#join-a-channel" aria-label="Permalink to &quot;Join a Channel&quot;">​</a></h3><ol><li>Click the <strong>+</strong> next to &quot;Channels&quot;</li><li>Browse public channels</li><li>Click &quot;Join&quot; on any channel</li></ol><h3 id="send-your-first-message" tabindex="-1">Send Your First Message <a class="header-anchor" href="#send-your-first-message" aria-label="Permalink to &quot;Send Your First Message&quot;">​</a></h3><ol><li>Select a channel from the sidebar</li><li>Type in the message box at the bottom</li><li>Press <strong>Enter</strong> to send</li></ol><h3 id="format-your-messages" tabindex="-1">Format Your Messages <a class="header-anchor" href="#format-your-messages" aria-label="Permalink to &quot;Format Your Messages&quot;">​</a></h3><p>Use Markdown for formatting:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>**bold text**</span></span>
<span class="line"><span>*italic text*</span></span>
<span class="line"><span>\`code\`</span></span>
<span class="line"><span>&gt; quote</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Learn about <a href="./features#channels">Channels and DMs</a></li><li>Set up <a href="./features#notifications">Notifications</a></li><li>Customize your <a href="./features#settings">Settings</a></li></ul><h2 id="need-help" tabindex="-1">Need Help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need Help?&quot;">​</a></h2><p>See the <a href="./troubleshooting">Troubleshooting</a> section or contact your system administrator.</p><hr><p><em>For administrators: See the <a href="./../admin/README">Admin Guide</a> for deployment and configuration.</em></p>`,28)])])}const g=a(n,[["render",r]]);export{p as __pageData,g as default};
